const rawItems = $input.all();
const listaConsolidada = [];

for (const item of rawItems) {
  const data = item.json;

  // 1. FILTRO DE CABECERA: Ignoramos la fila de texto donde dice "Fecha"
  if (data.__EMPTY === 'Fecha' || !data.__EMPTY) {
    continue;
  }

  // 2. FILTRO DE PIE DE PÁGINA: Las fechas reales del BCE vienen como "YYYY-MM-DD" (ej: 2010-02-01)
  // Si la celda no tiene un guion, significa que es una nota aclaratoria del final del Excel
  if (!data.__EMPTY.includes('-')) {
    continue;
  }

  // 3. PARSEO SEGURO: Convertimos los strings de los índices a números reales
  const ieeGlobal = parseFloat(data.__EMPTY_1);
  const comercio = parseFloat(data.__EMPTY_2);
  const construccion = parseFloat(data.__EMPTY_3);
  const manufactura = parseFloat(data.__EMPTY_4);
  const servicios = parseFloat(data.__EMPTY_5);

  // Guardamos la fecha fiscal limpia en una constante
  const fechaFiscalLimpia = data.__EMPTY.trim();

  // 4. MAPEO HOMOGÉNEO: Estructuramos con el mismo estándar de la base de datos
  listaConsolidada.push({
    json: {
      INDICADOR: "EXPECTATIVAS_EMPRESARIALES",
      FECHA_FISCAL: fechaFiscalLimpia,   // ◄--- NUEVA: Expuesta a nivel raíz para evitar duplicados
      FECHA_EXTRACCION: new Date(),     // Objeto Date nativo de JS para evitar error NJS-011
      ESTADO: "COMPLETO",
      NECESITA_RESPALDO: 0,             // Corregido: entero estático (0 = No necesita respaldo)
      DETALLE_ERROR: "",
      // Todo el vector sectorial empaquetado en el documento JSON nativo
      DATOS_JSON: JSON.stringify({
        fecha_fiscal: fechaFiscalLimpia,
        iee_global: isNaN(ieeGlobal) ? null : ieeGlobal,
        comercio: isNaN(comercio) ? null : comercio,
        construccion: isNaN(construccion) ? null : construccion,
        manufactura: isNaN(manufactura) ? null : manufactura,
        servicios: isNaN(servicios) ? null : servicios,
        fuente: "Banco Central del Ecuador",
        ruta_logica: "BCE/SECTOR_REAL/EXPECTATIVAS_EMPRESARIALES" // Estructura de carpetas virtuales
      })
    }
  });
}

return listaConsolidada;

const rawItems = $input.all();
const listaConsolidada = [];

// Expresión regular para cazar la fecha de actualización (ej: 04/06/2026)
const regexFechaActualizacion = /(\d{2})\/(\d{2})\/(\d{4})/;
let periodoFiscalDetectado = "";

// =========================================================================
// FASE 1: DETECCIÓN DINÁMICA DEL PERIODO FISCAL Y MAPEO DE CABECERAS
// =========================================================================
let llavesColumnas = {};
let indiceCabecera = -1;

for (let i = 0; i < Math.min(rawItems.length, 15); i++) {
  const fila = rawItems[i].json;
  const textoFila = JSON.stringify(fila);

  // A. Intentamos extraer la fecha real de actualización del reporte
  if (textoFila.includes("ACTUALIZACION")) {
    const match = textoFila.match(regexFechaActualizacion);
    if (match) {
      periodoFiscalDetectado = `${match[3]}-${match[2]}`; // Construye "YYYY-MM" (ej: "2026-06")
    }
  }

  // B. Detectamos la fila exacta donde inician las cabeceras reales del directorio
  if (textoFila.includes("RUC") && textoFila.includes("EXPEDIENTE")) {
    indiceCabecera = i;
    llavesColumnas = fila; // Guardamos el mapeo interno de propiedades de n8n (__EMPTY, __EMPTY_1...)
    break;
  }
}

// Fallback de contingencia si no se detecta la fecha en el archivo
if (!periodoFiscalDetectado) {
  const hoy = new Date();
  periodoFiscalDetectado = `${hoy.getFullYear()}-${String(hoy.getMonth() + 1).padStart(2, '0')}`;
}

// Función auxiliar para revertir el formato monetario de Ecuador ("48.200,00" -> 48200.00)
function parsearCapitalEcuador(val) {
  if (val === undefined || val === null || val === '') return 0;
  let limpio = val.toString().trim();
  limpio = limpio.replace(/\./g, ''); // Eliminamos puntos de miles
  limpio = limpio.replace(/,/g, '.'); // Cambiamos coma decimal por punto lógico
  const num = parseFloat(limpio);
  return isNaN(num) ? 0 : num;
}

// Invertimos las llaves para poder buscar la columna de n8n dinámicamente por su nombre de texto real
const mapaInvertido = {};
for (const [claveN8n, nombreColumna] of Object.entries(llavesColumnas)) {
  if (nombreColumna) {
    mapaInvertido[nombreColumna.toString().trim().toUpperCase()] = claveN8n;
  }
}

// =========================================================================
// FASE 2: PROCESAMIENTO Y DEPURACIÓN MATRICIAL (Skip de cabeceras y basura)
// =========================================================================
// Iniciamos justo después de la fila de cabecera detectada
const inicioDatos = indiceCabecera !== -1 ? indiceCabecera + 1 : 5;

for (let i = inicioDatos; i < rawItems.length; i++) {
  const data = rawItems[i].json;

  // Extraemos las dimensiones clave usando nuestro mapa dinámico e indestructible
  const ruc = data[mapaInvertido["RUC"]] ? data[mapaInvertido["RUC"]].toString().trim() : "";
  const expediente = data[mapaInvertido["EXPEDIENTE"]] ? data[mapaInvertido["EXPEDIENTE"]].toString().trim() : "";
  const nombreCompania = data[mapaInvertido["NOMBRE"]] ? data[mapaInvertido["NOMBRE"]].toString().trim() : "";

  // Escudo de seguridad: Si no hay RUC ni expediente válido, es una fila vacía o basura del pie de página
  if (!ruc && !expediente) continue;
  if (ruc === "RUC" || nombreCompania.includes("DIRECTORIO")) continue;

  // EL ESCUDO ANTI-SOBREESCRITURA (FECHA_FISCAL Compuesta)
  // Combinamos el periodo del reporte con el identificador único de la empresa
  const identificadorEmpresa = ruc || expediente;
  const fechaFiscalClave = `${periodoFiscalDetectado}_${identificadorEmpresa}`.replace(/\s+/g, '');

  listaConsolidada.push({
    json: {
      INDICADOR: "SUPERCIAS_DIRECTORIO",
      FECHA_FISCAL: fechaFiscalClave.substring(0, 150),
      FECHA_EXTRACCION: new Date(),
      ESTADO: "COMPLETO",
      NECESITA_RESPALDO: 0,
      DETALLE_ERROR: "",
      DATOS_JSON: JSON.stringify({
        periodo_reporte: periodoFiscalDetectado,
        empresa_metadata: {
          expediente: expediente,
          ruc: ruc,
          nombre: nombreCompania,
          situacion_legal: data[mapaInvertido["SITUACIÓN LEGAL"]] || "",
          fecha_constitucion: data[mapaInvertido["FECHA_CONSTITUCION"]] || "",
          tipo_compania: data[mapaInvertido["TIPO"]] || ""
        },
        ubicacion: {
          pais: data[mapaInvertido["PAÍS"]] || "ECUADOR",
          region: data[mapaInvertido["REGIÓN"]] || "",
          provincia: data[mapaInvertido["PROVINCIA"]] || "",
          canton: data[mapaInvertido["CANTÓN"]] || "",
          ciudad: data[mapaInvertido["CIUDAD"]] || "",
          calle: data[mapaInvertido["CALLE"]] || "",
          numero: data[mapaInvertido["NÚMERO"]] || "",
          interseccion: data[mapaInvertido["INTERSECCIÓN"]] || "",
          barrio: data[mapaInvertido["BARRIO"]] || "",
          telefono: data[mapaInvertido["TELÉFONO"]] || ""
        },
        financiero_ciiu: {
          representante: data[mapaInvertido["REPRESENTANTE"]] || "",
          cargo: data[mapaInvertido["CARGO"]] || "",
          capital_suscrito: parsearCapitalEcuador(data[mapaInvertido["CAPITAL SUSCRITO"]]),
          ciiu_nivel1: data[mapaInvertido["CIIU NIVEL 1"]] || "",
          ciiu_nivel6: data[mapaInvertido["CIIU NIVEL 6"]] || "",
          ultimo_balance_anio: data[mapaInvertido["ÚLTIMO BALANCE"]] || ""
        },
        fuente: "Superintendencia de Compañías, Valores y Seguros del Ecuador",
        ruta_logica: "SUPERCIAS/REPORTES/DIRECTORIO_COMPANIAS"
      })
    }
  });
}

return listaConsolidada;

// 1. Capturamos el payload del error del HTTP que haya gatillado el nodo
const rawItem = $input.first().json;
const hoy = new Date();

// 2. Formateamos la fecha de salvavidas para la FECHA_FISCAL (YYYY-MM-DD)
const anio = hoy.getFullYear();
const mes = String(hoy.getMonth() + 1).padStart(2, '0');
const dia = String(hoy.getDate()).padStart(2, '0');
const fechaFallback = `${anio}-${mes}-${dia}`;

let mensajeError = "Error indeterminado en la ingesta de fuentes mensuales.";
let urlAfectada = "";

// Extraemos de forma segura el mensaje técnico y la URI del error de n8n
if (rawItem.error) {
  mensajeError = rawItem.error.message || JSON.stringify(rawItem.error);
  // n8n suele adjuntar la URL del fallo en el objeto de contexto de Axios
  urlAfectada = rawItem.error.context?.url || "";
} else if (rawItem.message) {
  mensajeError = rawItem.message;
}

// 3. ALGORITMO DE CLASIFICACIÓN DINÁMICA DE INDICADORES
// Analizamos las firmas de texto en el error o la URL para saber a quién pertenece
let indicadorTarget = "MENSUAL_DESCONOCIDO";
let rutaLogicaTarget = "COYUNTURA/MENSUAL/CONTINGENCIA";

const rastroTexto = (mensajeError + " " + urlAfectada).toLowerCase();

if (rastroTexto.includes("supercias") || rastroTexto.includes("mercadodevalores") || rastroTexto.includes("companias")) {
  indicadorTarget = "SUPERCIAS_DIRECTORIO";
  rutaLogicaTarget = "SUPERCIAS/REPORTES/DIRECTORIO_COMPANIAS";
} else if (rastroTexto.includes("enemdu") || rastroTexto.includes("laboral") || rastroTexto.includes("empleo")) {
  indicadorTarget = "INEC_ENEMDU_MENSUAL";
  rutaLogicaTarget = "INEC/ENEMDU/MENSUAL";
} else if (rastroTexto.includes("bce") || rastroTexto.includes("central") || rastroTexto.includes("reportes")) {
  indicadorTarget = "BCE_MENSUAL_GENERAL";
  rutaLogicaTarget = "BCE/MENSUAL/GENERAL";
}

// 4. RETORNAMOS EL OBJETO DE AUDITORÍA HERIDO HOMOLOGADO PARA ORACLE
return [{
  json: {
    INDICADOR: indicadorTarget, // ◄--- Mutación dinámica del indicador afectado
    FECHA_FISCAL: `${fechaFallback}_ERR_MENSUAL`, // Llave controlada del día anti-duplicados
    FECHA_EXTRACCION: hoy,
    ESTADO: "INCOMPLETO",
    NECESITA_RESPALDO: 1, // Enciende la bandera de soporte técnico en la base de datos
    DETALLE_ERROR: `Fallo Crítico Mensual [${indicadorTarget}]: ${mensajeError}`.substring(0, 4000),
    DATOS_JSON: JSON.stringify({
      error: true,
      fase: "INGESTA_HTTP_MENSUAL",
      mensaje_tecnico: mensajeError,
      url_origen: urlAfectada,
      fuente: "Consolidador de Contingencias Mensuales Orquestado",
      ruta_logica: rutaLogicaTarget
    })
  }
}];
